import{_ as e,a}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as i,o as l,c as n,a2 as d}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"User Rate Limits","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/Safety/user-rate-limits.md","filePath":"vi-VN/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),s={name:"vi-VN/Safety/user-rate-limits.md"};function r(o,t,c,h,p,u){return l(),n("div",null,[...t[0]||(t[0]=[d('<h1 id="user-rate-limits" tabindex="-1">User Rate Limits <a class="header-anchor" href="#user-rate-limits" aria-label="Permalink to &quot;User Rate Limits&quot;">​</a></h1><p>User rate limits kiểm soát regular users hoặc visitors có thể upload files từ homepage thường xuyên đến mức nào. Tính năng này giúp tránh public upload pages bị lạm dụng.</p><p>Feature này chỉ ảnh hưởng homepage uploads. Admin uploads và uploads bằng API Tokens không bị user rate limits giới hạn.</p><h2 id="cau-hinh-o-đau" tabindex="-1">Cấu hình ở đâu <a class="header-anchor" href="#cau-hinh-o-đau" aria-label="Permalink to &quot;Cấu hình ở đâu&quot;">​</a></h2><p>Mở admin panel, rồi vào:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+e+'" alt="User rate limit settings" loading="lazy"></p><h2 id="enable-rate-limits" tabindex="-1">Enable Rate Limits <a class="header-anchor" href="#enable-rate-limits" aria-label="Permalink to &quot;Enable Rate Limits&quot;">​</a></h2><p>Sau khi bật <code>Enable Rate Limits</code>, ImgBed track recent uploads theo uploader IP address.</p><p>Default values:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Detection window</td><td>1.5 hours</td><td>Khoảng thời gian upload records được tính ngược lại.</td></tr><tr><td>Max file count</td><td>20</td><td>Số files tối đa được phép trong detection window.</td></tr><tr><td>Single file size limit</td><td>20 MB</td><td>Kích thước tối đa của một file.</td></tr><tr><td>Total upload size limit</td><td>200 MB</td><td>Tổng upload size tối đa trong detection window.</td></tr></tbody></table><p>Ví dụ, với window 1.5 giờ, 20 files, 20 MB mỗi file và tổng 200 MB, uploads từ cùng IP sẽ bị block khi vượt bất kỳ configured limit nào.</p><h2 id="excluding-file-types" tabindex="-1">Excluding File Types <a class="header-anchor" href="#excluding-file-types" aria-label="Permalink to &quot;Excluding File Types&quot;">​</a></h2><p><code>Excluded upload file types</code> chặn regular users hoặc visitors upload các file categories đã chọn.</p><p>Available categories:</p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif và các image files tương tự</td></tr><tr><td>Videos</td><td>mp4, webm, mov và các video files tương tự</td></tr><tr><td>Audio</td><td>mp3, flac, wav và các audio files tương tự</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx và các document files tương tự</td></tr><tr><td>Other</td><td>Files ngoài các categories trên, như zip, rar, exe, apk</td></tr></tbody></table><p>Mặc định không type nào được chọn, nghĩa là được phép.</p><p>Khi click một type, type đó được highlight, nghĩa là bị block.</p><p>Nếu chọn <code>Other</code>, visitors upload zip hoặc rar files sẽ bị block và được báo rằng file type này không được hỗ trợ.</p><h2 id="block-messages" tabindex="-1">Block Messages <a class="header-anchor" href="#block-messages" aria-label="Permalink to &quot;Block Messages&quot;">​</a></h2><p>Khi một limit được trigger, users sẽ thấy message tương ứng:</p><p><img src="'+a+'" alt="Too frequent upload message" loading="lazy"></p><table tabindex="0"><thead><tr><th>Scenario</th><th>Message Meaning</th></tr></thead><tbody><tr><td>Single file too large</td><td>File quá lớn, nên compress trước khi upload.</td></tr><tr><td>File type blocked</td><td>File type này không được hỗ trợ. Hãy bỏ file đó rồi thử lại.</td></tr><tr><td>Uploads too frequent</td><td>Recent uploads quá dày, có hiển thị retry time.</td></tr><tr><td>Total size too high</td><td>Recent total upload size quá cao, có hiển thị retry time.</td></tr></tbody></table><h2 id="khi-nao-nen-enable" tabindex="-1">Khi nào nên Enable <a class="header-anchor" href="#khi-nao-nen-enable" aria-label="Permalink to &quot;Khi nào nên Enable&quot;">​</a></h2><p>Bật user rate limits nếu upload homepage của bạn public accessible.</p><p>Các lý do thường gặp:</p><ul><li>Bạn lo ngại scripted bulk uploads.</li><li>Bạn muốn giới hạn large visitor uploads.</li><li>Bạn chỉ muốn regular users upload images, không upload archives hoặc installers.</li><li>Bạn muốn giữ public upload khả dụng nhưng kiểm soát resource usage.</li></ul><p>Nếu site chỉ dùng cho cá nhân, hoặc chỉ administrators upload, có thể để disabled.</p>',28)])])}const f=i(s,[["render",r]]);export{b as __pageData,f as default};
